#!/usr/bin/env python3
"""
Benchmark script for Python TemplateFlow implementation.
Measures performance of key operations for comparison with Rust.
"""

import time
import json
import statistics
from pathlib import Path
import sys

try:
    import templateflow
    from templateflow import api
except ImportError:
    print("Error: TemplateFlow Python package not installed.")
    print("Install with: pip install templateflow")
    sys.exit(1)


def time_operation(func, iterations=10):
    """Time an operation over multiple iterations."""
    times = []
    for _ in range(iterations):
        start = time.perf_counter()
        result = func()
        end = time.perf_counter()
        times.append(end - start)

    return {
        'min': min(times),
        'max': max(times),
        'mean': statistics.mean(times),
        'median': statistics.median(times),
        'stdev': statistics.stdev(times) if len(times) > 1 else 0,
        'iterations': iterations
    }


def benchmark_list_templates():
    """Benchmark listing all templates."""
    def operation():
        return api.templates()

    return time_operation(operation, iterations=20)


def benchmark_list_files_single_entity():
    """Benchmark listing files with single entity query."""
    def operation():
        return api.ls('MNI152Lin', resolution='01')

    return time_operation(operation, iterations=20)


def benchmark_list_files_multiple_entities():
    """Benchmark listing files with multiple entity query."""
    def operation():
        return api.ls('MNI152Lin', resolution='01', suffix='T1w')

    return time_operation(operation, iterations=20)


def benchmark_get_metadata():
    """Benchmark getting template metadata."""
    def operation():
        return api.get_metadata('MNI152Lin')

    return time_operation(operation, iterations=20)


def benchmark_get_citations():
    """Benchmark getting template citations."""
    def operation():
        return api.get_citations('MNI152Lin')

    return time_operation(operation, iterations=20)


def benchmark_skeleton_update():
    """Benchmark skeleton update check."""
    def operation():
        # This doesn't actually update, just checks
        from templateflow.conf import update_skel
        # Simulate the check without actual download
        return True

    return time_operation(operation, iterations=5)


def benchmark_query_all_templates_t1w():
    """Benchmark querying all templates for T1w files."""
    def operation():
        results = []
        for template in api.templates():
            files = api.ls(template, suffix='T1w')
            results.extend(files)
        return results

    return time_operation(operation, iterations=5)


def main():
    print("TemplateFlow Python Benchmark")
    print("=" * 50)
    print(f"Python version: {sys.version}")
    print(f"TemplateFlow version: {templateflow.__version__ if hasattr(templateflow, '__version__') else 'unknown'}")
    print()

    benchmarks = {
        'list_templates': {
            'description': 'List all available templates',
            'func': benchmark_list_templates
        },
        'list_files_single_entity': {
            'description': 'List files with single entity (resolution=01)',
            'func': benchmark_list_files_single_entity
        },
        'list_files_multiple_entities': {
            'description': 'List files with multiple entities (resolution=01, suffix=T1w)',
            'func': benchmark_list_files_multiple_entities
        },
        'get_metadata': {
            'description': 'Get template metadata for MNI152Lin',
            'func': benchmark_get_metadata
        },
        'get_citations': {
            'description': 'Get citations for MNI152Lin',
            'func': benchmark_get_citations
        },
        'query_all_templates_t1w': {
            'description': 'Query all templates for T1w files',
            'func': benchmark_query_all_templates_t1w
        },
    }

    results = {}

    for name, info in benchmarks.items():
        print(f"Running: {info['description']}...")
        try:
            result = info['func']()
            results[name] = {
                'description': info['description'],
                'timing': result,
                'error': None
            }
            print(f"  Mean time: {result['mean']*1000:.2f}ms")
            print(f"  Min/Max: {result['min']*1000:.2f}ms / {result['max']*1000:.2f}ms")
        except Exception as e:
            results[name] = {
                'description': info['description'],
                'timing': None,
                'error': str(e)
            }
            print(f"  Error: {e}")
        print()

    # Save results to JSON
    output_file = Path(__file__).parent / 'python_benchmark_results.json'
    with open(output_file, 'w') as f:
        json.dump(results, f, indent=2)

    print(f"Results saved to: {output_file}")


if __name__ == '__main__':
    main()

